// initial-setup.bicep
// Deploy a resource group structure and baseline budget
// Run: az deployment sub create --template-file initial-setup.bicep --location eastus

targetScope = 'subscription'

param environments array = ['dev', 'staging', 'prod']
param location string = 'eastus'
param appName string = 'myapp'
param ownerEmail string

// Create a resource group per environment
resource rgs 'Microsoft.Resources/resourceGroups@2022-09-01' = [for env in environments: {
  name: 'rg-${appName}-${env}-${location}'
  location: location
  tags: {
    Environment: env
    Application: appName
    Owner: ownerEmail
  }
}]

// Budget at subscription scope
resource budget 'Microsoft.Consumption/budgets@2021-10-01' = {
  name: 'budget-monthly-${appName}'
  properties: {
    category: 'Cost'
    amount: 50
    timeGrain: 'Monthly'
    timePeriod: {
      startDate: '2024-01-01'
      endDate: '2025-12-31'
    }
    notifications: {
      actualGT80: {
        enabled: true
        operator: 'GreaterThan'
        threshold: 80
        thresholdType: 'Actual'
        contactEmails: [ownerEmail]
      }
    }
  }
}

output rgNames array = [for (env, i) in environments: rgs[i].name]
